//! personality_steering.rs
//! ========================
//!
//! Runtime mirror of `Gnosis.PersonalityLogitSteering`
//! (open-source/gnosis-math/Gnosis/PersonalityLogitSteering.lean).
//!
//! A learned personality (from a Pensieve text history) is compiled into a
//! bounded, **signed** logit-selection filter: a per-token bias added to the
//! model's logits right before the argmax, so a Shield/Ombuds halogram selects
//! language like the real correspondent — steering when the harmony moves, like
//! Coltrane.
//!
//! Two contracts, both proved in Lean and pinned by the tests below:
//!
//!   Promote-only core (`Nat`): ENVELOPE / NON-FORBIDDING / IDENTITY / MONOTONE /
//!   COLTRANE-GATE — captures positive tells ("this person SHOUTS / says X a lot").
//!
//!   Signed envelope (`Int`): for *anti-tells* ("this person never uses emoji"),
//!   the bias goes negative, clamped into `[-cap, +cap]` with a floor so no logit
//!   is sent to -inf (softmax support preserved). Proved: `base - cap <= steered
//!   <= base + cap`.
//!
//! Applied at the seam in `model.rs::decode_next_fast_argmax_once`, mirroring the
//! opt-in `repetition_penalty` loop. Default OFF so the Paris quality gate stays
//! pure argmax.

// ─────────────────────────────────────────────────────────────────────────────
// Promote-only core (mirror of the Nat-side Lean definitions)
// ─────────────────────────────────────────────────────────────────────────────

/// Mirror of Lean `SteeringSignature`. Non-negative fixed-point gains/caps.
#[derive(Clone, Debug, PartialEq, Eq)]
pub struct SteeringSignature {
    pub behavioral_gain: u32,
    pub aesthetic_gain: u32,
    pub prosody_gain: u32,
    pub harmonic_gain: u32,
    /// Full bias envelope at a terminal-prosody boundary.
    pub steer_cap: u32,
    /// Smaller envelope off-boundary. Well-formed keeps `rest_cap <= steer_cap`.
    pub rest_cap: u32,
}

impl SteeringSignature {
    pub fn neutral(steer_cap: u32, rest_cap: u32) -> Self {
        Self {
            behavioral_gain: 0,
            aesthetic_gain: 0,
            prosody_gain: 0,
            harmonic_gain: 0,
            steer_cap,
            rest_cap,
        }
    }
    pub fn is_well_formed(&self) -> bool {
        self.rest_cap <= self.steer_cap
    }
}

/// Mirror of Lean `CandidateAffinity`: per-token match across the four wave axes.
#[derive(Clone, Copy, Debug, PartialEq, Eq, Default)]
pub struct CandidateAffinity {
    pub behavioral_match: u32,
    pub aesthetic_match: u32,
    pub prosody_match: u32,
    pub harmonic_match: u32,
}

/// Lean `weightedAffinity`. Saturating so the contract holds at the u32 ceiling.
pub fn weighted_affinity(sig: &SteeringSignature, c: &CandidateAffinity) -> u32 {
    sig.behavioral_gain
        .saturating_mul(c.behavioral_match)
        .saturating_add(sig.aesthetic_gain.saturating_mul(c.aesthetic_match))
        .saturating_add(sig.prosody_gain.saturating_mul(c.prosody_match))
        .saturating_add(sig.harmonic_gain.saturating_mul(c.harmonic_match))
}

pub fn active_cap(sig: &SteeringSignature, at_boundary: bool) -> u32 {
    if at_boundary {
        sig.steer_cap
    } else {
        sig.rest_cap
    }
}

/// Lean `steerBias` — weighted affinity clamped into the active envelope.
pub fn steer_bias(sig: &SteeringSignature, c: &CandidateAffinity, at_boundary: bool) -> u32 {
    weighted_affinity(sig, c).min(active_cap(sig, at_boundary))
}

// ─────────────────────────────────────────────────────────────────────────────
// Signed envelope (mirror of the Int-side Lean definitions)
// ─────────────────────────────────────────────────────────────────────────────

/// Lean `clampSym` — symmetric clamp of a net affinity into `[-cap, +cap]`.
pub fn clamp_sym(x: i64, cap: u32) -> i64 {
    let cap = cap as i64;
    if x > cap {
        cap
    } else if x < -cap {
        -cap
    } else {
        x
    }
}

/// Lean `signedSteeredLogit` (integer form). Two-sided bounded, never -inf.
pub fn signed_steered_logit(base: i64, net_affinity: i64, cap: u32) -> i64 {
    base + clamp_sym(net_affinity, cap)
}

// ─────────────────────────────────────────────────────────────────────────────
// Orthographic style: the "voice tells" (caps, punctuation, emoji, emoticons)
// ─────────────────────────────────────────────────────────────────────────────

/// Surface features of a single token string — the tells that make text feel
/// like a specific person. Computed per BPE token at learn time and decode time.
#[derive(Clone, Copy, Debug, Default, PartialEq, Eq)]
pub struct TokenStyleFeatures {
    /// >=2 cased letters, all uppercase: SHOUTING / emphasis.
    pub all_caps: bool,
    /// has letters, none uppercase: lowercase-only register.
    pub all_lower: bool,
    pub has_exclaim: bool,
    pub has_question: bool,
    /// `...` or the `…` ellipsis: trailing / silence residue.
    pub has_ellipsis: bool,
    /// a terminal `.` (firm cadence close).
    pub has_terminal_period: bool,
    /// a Unicode emoji / pictograph.
    pub has_emoji: bool,
    /// a plaintext ASCII emoticon: `:)` `:-)` `;)` `<3` `^^` `:P`.
    pub has_ascii_emoticon: bool,
}

pub fn token_style_features(tok: &str) -> TokenStyleFeatures {
    let letters: Vec<char> = tok.chars().filter(|c| c.is_alphabetic()).collect();
    let has_letters = !letters.is_empty();
    let cased: Vec<char> = letters.iter().copied().filter(|c| c.is_alphabetic()).collect();
    let any_upper = cased.iter().any(|c| c.is_uppercase());
    let any_lower = cased.iter().any(|c| c.is_lowercase());
    let all_caps = cased.len() >= 2 && any_upper && !any_lower;
    let all_lower = has_letters && !any_upper;

    let has_ellipsis = tok.contains('…') || tok.contains("...");
    let has_question = tok.contains('?');
    let has_exclaim = tok.contains('!');
    // terminal period that is not part of an ellipsis
    let has_terminal_period = tok.trim_end().ends_with('.') && !has_ellipsis;
    let has_emoji = tok.chars().any(is_emoji_char);
    let has_ascii_emoticon = contains_ascii_emoticon(tok);

    TokenStyleFeatures {
        all_caps,
        all_lower,
        has_exclaim,
        has_question,
        has_ellipsis,
        has_terminal_period,
        has_emoji,
        has_ascii_emoticon,
    }
}

fn is_emoji_char(c: char) -> bool {
    let u = c as u32;
    (0x1F300..=0x1FAFF).contains(&u)   // pictographs, emoticons, symbols, supplemental
        || (0x2600..=0x27BF).contains(&u) // misc symbols + dingbats
        || (0x1F1E6..=0x1F1FF).contains(&u) // regional indicators (flags)
        || u == 0x2764 // heart
        || u == 0xFE0F // variation selector-16 (emoji presentation)
}

fn contains_ascii_emoticon(tok: &str) -> bool {
    const EMOTICONS: [&str; 12] = [
        ":)", ":-)", ":(", ":-(", ";)", ";-)", ":d", ":-d", ":p", ":-p", "<3", "^^",
    ];
    let lower = tok.to_ascii_lowercase();
    EMOTICONS.iter().any(|e| lower.contains(e))
}

/// A person's SIGNED orthographic preferences, learned as
/// `person_rate(feature) - baseline_rate(feature)` in fixed point. Positive = a
/// tell they lean into; negative = an anti-tell they avoid (e.g. emoji for an
/// emoji-hater). Absence is signal.
#[derive(Clone, Copy, Debug, Default, PartialEq, Eq)]
pub struct StylePreferences {
    pub caps: i32,
    pub lower: i32,
    pub exclaim: i32,
    pub question: i32,
    pub ellipsis: i32,
    pub period: i32,
    pub emoji: i32,
    pub ascii_emoticon: i32,
}

/// Per-feature occurrence counts over a corpus (person or baseline).
#[derive(Clone, Copy, Debug, Default)]
pub struct StyleCounts {
    pub tokens: u64,
    pub caps: u64,
    pub lower: u64,
    pub exclaim: u64,
    pub question: u64,
    pub ellipsis: u64,
    pub period: u64,
    pub emoji: u64,
    pub ascii_emoticon: u64,
}

impl StyleCounts {
    /// Accumulate one token's features.
    pub fn observe(&mut self, tok: &str) {
        let f = token_style_features(tok);
        self.tokens += 1;
        self.caps += f.all_caps as u64;
        self.lower += f.all_lower as u64;
        self.exclaim += f.has_exclaim as u64;
        self.question += f.has_question as u64;
        self.ellipsis += f.has_ellipsis as u64;
        self.period += f.has_terminal_period as u64;
        self.emoji += f.has_emoji as u64;
        self.ascii_emoticon += f.has_ascii_emoticon as u64;
    }
}

impl StylePreferences {
    /// THE LEARNING STEP (orthography). Signed preference per feature =
    /// `(person_rate - baseline_rate) * scale`. An emoji-hater whose `emoji`
    /// count is ~0 against a baseline that uses emoji gets a negative `emoji`
    /// preference, demoting emoji tokens; their `:)` usage above baseline gets a
    /// positive `ascii_emoticon` preference.
    pub fn learn(person: &StyleCounts, baseline: &StyleCounts, scale: i32) -> Self {
        let pt = person.tokens.max(1) as f64;
        let bt = baseline.tokens.max(1) as f64;
        let s = scale as f64;
        let pref = |p: u64, b: u64| -> i32 { (((p as f64 / pt) - (b as f64 / bt)) * s).round() as i32 };
        Self {
            caps: pref(person.caps, baseline.caps),
            lower: pref(person.lower, baseline.lower),
            exclaim: pref(person.exclaim, baseline.exclaim),
            question: pref(person.question, baseline.question),
            ellipsis: pref(person.ellipsis, baseline.ellipsis),
            period: pref(person.period, baseline.period),
            emoji: pref(person.emoji, baseline.emoji),
            ascii_emoticon: pref(person.ascii_emoticon, baseline.ascii_emoticon),
        }
    }
}

/// Signed per-axis affinity of one token, from its surface features weighted by
/// the personality's signed preferences. Punctuation/cadence → prosody; caps and
/// emphasis → behavioral; register/emoji/emoticons → aesthetic (+ behavioral).
#[derive(Clone, Copy, Debug, Default, PartialEq, Eq)]
pub struct SignedAxisAffinity {
    pub behavioral: i32,
    pub aesthetic: i32,
    pub prosody: i32,
    pub harmonic: i32,
}

pub fn orthographic_affinity(tok: &str, prefs: &StylePreferences) -> SignedAxisAffinity {
    let f = token_style_features(tok);
    let mut a = SignedAxisAffinity::default();
    if f.all_caps {
        a.behavioral += prefs.caps;
        a.aesthetic += prefs.caps / 2;
    }
    if f.all_lower {
        a.aesthetic += prefs.lower;
    }
    if f.has_exclaim {
        a.behavioral += prefs.exclaim;
    }
    if f.has_question {
        a.prosody += prefs.question;
    }
    if f.has_ellipsis {
        a.prosody += prefs.ellipsis;
    }
    if f.has_terminal_period {
        a.prosody += prefs.period;
    }
    if f.has_emoji {
        a.aesthetic += prefs.emoji;
        a.behavioral += prefs.emoji / 2;
    }
    if f.has_ascii_emoticon {
        a.aesthetic += prefs.ascii_emoticon;
        a.behavioral += prefs.ascii_emoticon / 2;
    }
    a
}

/// Fold a signed per-axis affinity through the signature gains into a single net
/// signed score (the input to `clamp_sym`).
pub fn fold_signed(sig: &SteeringSignature, a: &SignedAxisAffinity) -> i64 {
    (sig.behavioral_gain as i64) * (a.behavioral as i64)
        + (sig.aesthetic_gain as i64) * (a.aesthetic as i64)
        + (sig.prosody_gain as i64) * (a.prosody as i64)
        + (sig.harmonic_gain as i64) * (a.harmonic as i64)
}

// ─────────────────────────────────────────────────────────────────────────────
// Compiled steering: the per-token bias vector applied at the decode seam
// ─────────────────────────────────────────────────────────────────────────────

/// A compiled per-token signed bias vector ready to add to logits.
/// `boundary_bias[id]` is the on-boundary bias (clamped to `±steer_cap`);
/// `rest_scale` shrinks it off-boundary (≈ `rest_cap / steer_cap`).
#[derive(Clone, Debug)]
pub struct PersonalitySteering {
    pub boundary_bias: Vec<f32>,
    pub rest_scale: f32,
}

impl PersonalitySteering {
    /// Compile the on-boundary bias vector from per-token net affinities and a
    /// signature: each token's bias is `clamp_sym(net, steer_cap)` — already in
    /// the signed envelope, so the runtime apply is a plain add.
    pub fn compile(sig: &SteeringSignature, net_affinities: &[i64]) -> Self {
        let boundary_bias = net_affinities
            .iter()
            .map(|&net| clamp_sym(net, sig.steer_cap) as f32)
            .collect();
        let rest_scale = if sig.steer_cap == 0 {
            0.0
        } else {
            (sig.rest_cap as f32) / (sig.steer_cap as f32)
        };
        Self {
            boundary_bias,
            rest_scale,
        }
    }

    /// Compile directly from the model's vocab strings + learned orthographic
    /// preferences (the end-to-end "learn the voice → bias vector" path).
    pub fn from_vocab_orthography(
        sig: &SteeringSignature,
        vocab: &[&str],
        prefs: &StylePreferences,
    ) -> Self {
        let nets: Vec<i64> = vocab
            .iter()
            .map(|t| fold_signed(sig, &orthographic_affinity(t, prefs)))
            .collect();
        Self::compile(sig, &nets)
    }

    /// Runtime apply at the decode seam. Mutates `logits` in place:
    /// `logits[id] += bias[id] * (at_boundary ? 1 : rest_scale)`. Additive,
    /// two-sided bounded; an empty vector is a no-op (base model unchanged).
    pub fn apply(&self, logits: &mut [f32], at_boundary: bool) {
        if self.boundary_bias.is_empty() {
            return;
        }
        let scale = if at_boundary { 1.0 } else { self.rest_scale };
        let n = logits.len().min(self.boundary_bias.len());
        for i in 0..n {
            logits[i] += self.boundary_bias[i] * scale;
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn witness_sig() -> SteeringSignature {
        SteeringSignature {
            behavioral_gain: 4,
            aesthetic_gain: 3,
            prosody_gain: 2,
            harmonic_gain: 2,
            steer_cap: 40,
            rest_cap: 8,
        }
    }
    fn on_voice() -> CandidateAffinity {
        CandidateAffinity {
            behavioral_match: 6,
            aesthetic_match: 5,
            prosody_match: 4,
            harmonic_match: 3,
        }
    }

    #[test]
    fn lean_promote_core_parity() {
        let sig = witness_sig();
        assert_eq!(weighted_affinity(&sig, &on_voice()), 53); // 4·6+3·5+2·4+2·3
        assert_eq!(steer_bias(&sig, &on_voice(), true), 40); // clamped to envelope
        assert_eq!(steer_bias(&sig, &on_voice(), false), 8); // rest envelope
    }

    #[test]
    fn lean_signed_witness_parity() {
        // Mirrors the closed-arithmetic witnesses in the Lean signed section.
        assert_eq!(clamp_sym(-30, 20), -20); // demoted to the floor, not past it
        assert_eq!(signed_steered_logit(100, -30, 20), 80); // emoji-hater demote
        assert_eq!(signed_steered_logit(100, 12, 20), 112); // :) promote
        assert_eq!(signed_steered_logit(100, 0, 20), 100); // IDENTITY
    }

    #[test]
    fn signed_envelope_two_sided() {
        // base - cap <= steered <= base + cap for any net.
        for net in [-1000i64, -41, -1, 0, 1, 41, 1000] {
            let out = signed_steered_logit(100, net, 40);
            assert!(out >= 100 - 40 && out <= 100 + 40);
        }
    }

    #[test]
    fn token_features_detect_tells() {
        assert!(token_style_features("HELLO").all_caps);
        assert!(!token_style_features("Hello").all_caps);
        assert!(token_style_features("hello").all_lower);
        assert!(token_style_features("wait…").has_ellipsis);
        assert!(token_style_features("really?").has_question);
        assert!(token_style_features("no!").has_exclaim);
        assert!(token_style_features("done.").has_terminal_period);
        assert!(token_style_features(":)").has_ascii_emoticon);
        assert!(token_style_features("😂").has_emoji);
        assert!(!token_style_features("done.").has_ellipsis);
    }

    #[test]
    fn emoji_hater_demotes_emoji_promotes_emoticon() {
        // Person: never uses emoji, loves :) and lowercase. Baseline uses emoji.
        let mut person = StyleCounts::default();
        for tok in ["hey", "there", ":)", "lol", "ok", "sure", ":)", "yeah"] {
            person.observe(tok);
        }
        let mut baseline = StyleCounts::default();
        for tok in ["Hey", "😂", "There", "👍", "Ok", "😀", "Sure", "Yeah"] {
            baseline.observe(tok);
        }
        let prefs = StylePreferences::learn(&person, &baseline, 1000);
        assert!(prefs.emoji < 0, "emoji should be an anti-tell: {}", prefs.emoji);
        assert!(prefs.ascii_emoticon > 0, "should promote :) -> {}", prefs.ascii_emoticon);

        let sig = witness_sig();
        // An emoji token folds to a NEGATIVE net (demote); a :) token POSITIVE.
        let emoji_net = fold_signed(&sig, &orthographic_affinity("😂", &prefs));
        let emoticon_net = fold_signed(&sig, &orthographic_affinity(":)", &prefs));
        assert!(emoji_net < 0, "emoji net should demote: {}", emoji_net);
        assert!(emoticon_net > 0, "emoticon net should promote: {}", emoticon_net);

        // Compiled into a vocab vector, the biases respect the signed envelope.
        let vocab = ["hey", "😂", ":)", "there"];
        let steering = PersonalitySteering::from_vocab_orthography(&sig, &vocab, &prefs);
        for &b in &steering.boundary_bias {
            assert!(b.abs() <= sig.steer_cap as f32);
        }
        assert!(steering.boundary_bias[1] < 0.0); // emoji demoted
        assert!(steering.boundary_bias[2] > 0.0); // :) promoted
    }

    #[test]
    fn apply_is_additive_two_sided_and_bounded() {
        let steering = PersonalitySteering {
            boundary_bias: vec![40.0, -40.0, 0.0],
            rest_scale: 0.2,
        };
        let mut logits = vec![100.0, 100.0, 100.0];
        steering.apply(&mut logits, true);
        assert_eq!(logits, vec![140.0, 60.0, 100.0]); // promote, demote, untouched
        let mut rest = vec![100.0, 100.0, 100.0];
        steering.apply(&mut rest, false);
        assert_eq!(rest, vec![108.0, 92.0, 100.0]); // off-boundary scaled down
    }

    #[test]
    fn empty_steering_is_noop() {
        let steering = PersonalitySteering {
            boundary_bias: vec![],
            rest_scale: 1.0,
        };
        let mut logits = vec![1.0, 2.0, 3.0];
        steering.apply(&mut logits, true);
        assert_eq!(logits, vec![1.0, 2.0, 3.0]); // IDENTITY: base model unchanged
    }
}
